// Tokens de cor das variações (alinhados ao DSS)
const VARIANTS = {
  default: {
    omnichannelColor: "#a4a6a5",
    sansysColor: "#a4a6a5",
    iconColor: "#a4a6a5",
  },
  colored: {
    omnichannelColor: "#0e7c6c", // verde/turquesa
    sansysColor: "#1d4971", // azul
    iconColor: "#0e7c6c", // verde/turquesa (mesmo tom do wordmark)
  },
} as const;

export type LogoVariant = keyof typeof VARIANTS;

export interface SansysOmnichannelLogoProps {
  className?: string;
  /** Preset de cores. 'default' = monocromático neutro, 'colored' = cores da marca. */
  variant?: LogoVariant;
  /**
   * Cor do wordmark "OmniChannel".
   * Sobrepõe a cor definida pelo variant.
   */
  omnichannelColor?: string;
  /**
   * Cor do wordmark "Sansys".
   * Sobrepõe a cor definida pelo variant.
   */
  sansysColor?: string;
  /**
   * Cor do ícone.
   * Sobrepõe a cor definida pelo variant.
   */
  iconColor?: string;
  /**
   * @deprecated Use `omnichannelColor` + `sansysColor` + `iconColor` para controle granular,
   * ou `variant` para presets. Mantido por compatibilidade.
   */
  color?: string;
}

export function SansysOmnichannelLogo({
  className = "h-12",
  variant = "default",
  omnichannelColor,
  sansysColor,
  iconColor,
  color, // legacy
}: SansysOmnichannelLogoProps) {
  const base = VARIANTS[variant];

  // Resolução de cor: prop explícita > legacy `color` > valor do variant
  const resolvedOmnichannel = omnichannelColor ?? color ?? base.omnichannelColor;
  const resolvedSansys = sansysColor ?? color ?? base.sansysColor;
  const resolvedIcon = iconColor ?? color ?? base.iconColor;

  return (
    <svg
      className={className}
      viewBox="0 0 120 42"
      xmlns="http://www.w3.org/2000/svg"
      aria-label="Sansys OmniChannel"
      role="img"
    >
      <g>
        {/* Ícone: símbolo circular com interações */}
        <path fill={resolvedIcon} d={ICON_PATH} />

        {/* Wordmark: OmniChannel */}
        <path fill={resolvedOmnichannel} d={OMNICHANNEL_PATH} />

        {/* Wordmark: Sansys */}
        <path fill={resolvedSansys} d={SANSYS_PATH} />
      </g>
    </svg>
  );
}
